import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface TrafficSource {
  source: string;
  value: number;
}

interface AnalyticsData {
  visitors: {
    current: number;
    changePercent: number;
  };
  pageViews: {
    current: number;
    changePercent: number;
  };
  bounceRate: {
    current: number;
    changePercent: number;
  };
  trafficSources: TrafficSource[];
}

export default function Widget() {
  const analyticsData = response.data as AnalyticsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1F2937' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Visitors
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#3B82F6' }}>
              {analyticsData.visitors.current.toLocaleString()}
            </Typography>
            <Typography variant="caption" sx={{ color: analyticsData.visitors.changePercent >= 0 ? '#10B981' : '#EF4444' }}>
              {analyticsData.visitors.changePercent >= 0 ? '+' : ''}{analyticsData.visitors.changePercent.toFixed(1)}%
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Page Views
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#3B82F6' }}>
              {analyticsData.pageViews.current.toLocaleString()}
            </Typography>
            <Typography variant="caption" sx={{ color: analyticsData.pageViews.changePercent >= 0 ? '#10B981' : '#EF4444' }}>
              {analyticsData.pageViews.changePercent >= 0 ? '+' : ''}{analyticsData.pageViews.changePercent.toFixed(1)}%
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Bounce Rate
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#3B82F6' }}>
              {analyticsData.bounceRate.current.toFixed(1)}%
            </Typography>
            <Typography variant="caption" sx={{ color: analyticsData.bounceRate.changePercent >= 0 ? '#EF4444' : '#10B981' }}>
              {analyticsData.bounceRate.changePercent >= 0 ? '+' : ''}{analyticsData.bounceRate.changePercent.toFixed(1)}%
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 140 }}>
            <PieChart
              data={analyticsData.trafficSources.map((source) => ({ value: source.value, label: source.source }))}
              color={['#3B82F6', '#2563EB', '#1E40AF', '#1E3A8A', '#1D4ED8']}
              sx={{
                '& .MuiPieElement-root': {
                  stroke: '#1F2937',
                  strokeWidth: 1,
                },
              }}
            />
          </Box>

          <Stack direction="row" spacing={0.5}>
            {analyticsData.trafficSources.map((source, index) => (
              <Chip
                key={index}
                label={source.source}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#374151', color: '#F3F4F6' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
